function [f] = pareto_plot(J1, bestJ1, idx_best_J1, J1_nom, J1_nom_sim, J1_solar, J1_balanced,...
                          J2, bestJ2, idx_best_J2, J2_nom, J2_nom_sim, J2_solar, J2_balanced,...
                          x_best_J1, x_best_J2, x_nom, x_balanced, idxo, showSingleObj,...
                          showImages, showLCOEContours, p, new_objs, LCOE_nom, LCOE_min, idx_min_LCOE, fig)
    if ~exist('fig','var')
        f = figure;
        pareto_color = 'b';
        pareto_shape = 's';
    else
        f = figure(fig);
        pareto_color = '#9999ff';
        pareto_shape = 'o';
    end

    % overall pareto front
    plot(J1(idxo),J2(idxo),pareto_shape,'Color',pareto_color,'MarkerEdgeColor',...
        pareto_color,'MarkerFaceColor',pareto_color,'HandleVisibility','on')
    hold on
    
    % utopia point
    plot(bestJ1,bestJ2,'gp','MarkerFaceColor','g','MarkerSize',20,'HandleVisibility','off')
    
    % RM3 nominal reference - report
    plot(J1_nom(1),    J2_nom(1),    'rd','MarkerFaceColor','r','HandleVisibility','off')
    plot(J1_nom_sim(1),J2_nom_sim(1),'rs','MarkerFaceColor','r','HandleVisibility','off')

    % RM3 nominal reference - wecsim
    plot(J1_nom(2),    J2_nom(2),    'md','HandleVisibility','off')
    plot(J1_nom_sim(2),J2_nom_sim(2),'ms','HandleVisibility','off')
    
    if showSingleObj  
        plot(J1(idx_best_J1),J2(idx_best_J1), 'gs','MarkerFaceColor','g','HandleVisibility','off')
        plot(J1(idx_best_J2),J2(idx_best_J2), 'rs','MarkerFaceColor','r','HandleVisibility','off')
        plot(J1(idx_min_LCOE),J2(idx_min_LCOE),'bs','MarkerFaceColor','b','HandleVisibility','off')
        plot(J1_balanced,J2_balanced,'ms','MarkerFaceColor','m','HandleVisibility','off')
    end
    
    % axis labels
    if new_objs
        xlabel('Average Electrical Power (kW)')
        ylabel('Structural and PTO Cost ($M)')
        xlim([.9*min(J1) 1.1*max(J1)])
        ylim([.9*min(J2) 1.05*max(J2)])
        [T_grid,Hs_grid] = meshgrid(p.T,p.Hs);
        P_wave = p.rho_w * p.g^2 / (64*pi) .* T_grid .* (Hs_grid.^2);
        CW_max = p.g * T_grid.^2 / (4*pi^2);
        P_rad_limit = P_wave .* CW_max .* p.eff_array;
        P_avg_rad_limit_kW = sum(P_rad_limit .* p.JPD/100, 'all') / 1000;
        xline(P_avg_rad_limit_kW,'k--','HandleVisibility','off')
    else
        xlabel('LCOE ($/kWh)')
        ylabel('Power Variation (%)')
        xlim([0 1])
        ylim([25 165])
    end
    
    title('Pareto Front')
    improvePlot
    
    % solar reference
    yellow = [1, .87, .2];
    plot(J1_solar, J2_solar,'o','MarkerSize',12,'MarkerEdgeColor',yellow,...
        'MarkerFaceColor',yellow,'HandleVisibility','off')
    % for the yellow color to work, do not use improvePlot below here
    
    % text labels
    sz = 14;
    text(J1_nom(1)+2,J2_nom(1)+.02,'RM3 Report','FontSize',sz)
    text(J1_nom(1)+.01,J2_nom(1)-5,'Actual [10]','FontSize',sz)
    text(J1_nom_sim(1)-.02,J2_nom_sim(1)+5,'RM3 Report','FontSize',sz)
    text(J1_nom_sim(1)+.03,J2_nom_sim(1)-.05,'Sim','FontSize',sz)

    text(J1_nom(2)+.03,J2_nom(2),'RM3 WecSim','FontSize',sz)
    text(J1_nom(2)+.01,J2_nom(2)-5,'Actual','FontSize',sz)
    text(J1_nom_sim(2)-.02,J2_nom_sim(2)+5,'RM3 WecSim','FontSize',sz)
    text(J1_nom_sim(2)+.03,J2_nom_sim(2),'Sim','FontSize',sz)

    text(bestJ1+.03,bestJ2-2,'Utopia Point','FontSize',sz)
    text(J1_solar+.03,J2_solar,'Solar','FontSize',sz)
    if showSingleObj
        xx = xlim;
        yy = ylim;
        x_spacing = (xx(2) - xx(1)) / 50;
        y_spacing = (yy(2) - yy(1)) / 50;
        text(J1(idx_best_J1)+.5*x_spacing, J2(idx_best_J1)+y_spacing,   {'Most','Power'},     'FontSize',sz)
        text(J1(idx_best_J2)+   x_spacing, J2(idx_best_J2)-y_spacing,    'Least Cost',        'FontSize',sz)
        text(J1(idx_min_LCOE)+  x_spacing, J2(idx_min_LCOE)+y_spacing,   {'Min','LCOE'},      'FontSize',sz)
        text(J1_balanced    -   x_spacing, J2_balanced    -9*y_spacing, {'Balanced','Design'},'FontSize',sz)
    end

    if showLCOEContours
        overlay_LCOE(p, LCOE_nom, LCOE_min)
    end

    if showImages   % small pictures of best geometries
        ylim([0.58, 2.3])

        upper_right = [.75 .512];
        mini_plot(upper_right,x_best_J1,p)

        lower_left = [.1 .18];
        mini_plot(lower_left,x_best_J2,p)
        
        balanced_pos = [.55 .35];
        mini_plot(balanced_pos,x_balanced,p)

        report_pos = [.21,.625];
        mini_plot(report_pos,x_nom(:,1),p)
        
        %wecsim_pos = [.28 .65];
        %mini_plot(wecsim_pos,x_nom(:,2),p)
    end

end

function mini_plot(pos, x, p)
    mini_plot_size = [.2 .22];
    axes('Position',[pos mini_plot_size])
    box on
    visualize_geometry(x,p,true);
    set(gca,'XTickLabel',[],'YTickLabel',[])
end

