function [f_unfiltered,f_filtered,f_nondim] = design_heuristics_plot(overallJ1, J1_best, idx_best_J1, x_best_J1, ...
                                     overallJ2, J2_best, idx_best_J2, ...
                                     overallX, idxo, J1_max, var_names, new_objs, p)

    % filter out pareto nonoptimal points
    J1_pareto = overallJ1(idxo);
    J2_pareto = overallJ2(idxo);
    X_pareto  = overallX(idxo,1:end-1); % get rid of material

    % filter out J1 above thresh
    idx_keep = J1_pareto < J1_max;

    J1_worst = overallJ1(idx_best_J2);
    J2_worst = overallJ2(idx_best_J1);

    % desired direction
    if new_objs
        dir = {'max','min'};
    else
        dir = {'min','min'};
    end

    % order from left to right on pareto front appearance, 
    % and normalize by optimal J1 values
    [X_pareto_ordered_normed,...
     J1_pareto_ordered_normed, ...
     J2_pareto_ordered_normed,...
     pct_angle] = pareto_order_normalize(J1_pareto(idx_keep), J2_pareto(idx_keep), ...
                                         X_pareto(idx_keep,:), dir,...
                                         J1_best, J1_worst, ...
                                         J2_best, J2_worst, x_best_J1(1:end-1), true);
    
    % apply filter
    backwards = strcmp(dir(1),'max');
    [X_filtered,pct_angle_even] = low_pass_filter(pct_angle, X_pareto_ordered_normed, backwards);
    
    % plot unfiltered
    f_unfiltered = figure;
    semilogy(pct_angle,X_pareto_ordered_normed)
    title('Unfiltered Design Heuristics')
    xlabel('Percent along the Pareto Curve')
    ylabel('Normalized Optimal Design Value')
    legend(var_names,'Location','eastoutside')
    ylim([0 15])
    improvePlot
    grid on
    set(gca,'YMinorGrid','on')
    
    % plot filtered
    cols = {'r:','r--','r-','r-.','r.',...       % bulk dims
            'b:','b--',...                       % PTO
            'g:','g--','g-','g-.','g.'}; % 'g*'  % structural
    f_filtered = figure;
    sub1 = subplot(2,1,1);
    for i=1:size(X_pareto_ordered_normed,2)
        semilogy(pct_angle_even,X_filtered(:,i),cols{i})
        hold on
    end
    
    % make fake major grid lines (didn't do "grid on" because then major lines show up for .2 .5 2 5 too)
    x_grid = [3 97];
    y_grid = [.1 1];
    y_tick = [.01 .02 .05 .1 .2 .5 1 2 5];
    for i=1:length(y_grid)
        plot(x_grid, y_grid(i)*[1 1],'Color',[.85 .85 .85]);
    end

    y_limits = [.9*min(X_filtered,[],'all'), 1.1*max(X_filtered,[],'all')];
    plot(pct_angle, y_limits(1) * ones(size(pct_angle)), 'ks','MarkerSize',5,'MarkerFaceColor','k','HandleVisibility','off')
    
    title('Design Trends')
    %xlabel('Percent along the Pareto Curve')
    ylabel('Normalized Optimal Design Value')
    ylim(y_limits)
    set(sub1,'YTick',y_tick)
    improvePlot
    
    leg1 = legend(var_names,'Location','eastoutside');
    set(sub1,'YMinorGrid','on')
    set(sub1,'XGrid','on')
    set(sub1, 'Children', flipud(get(sub1, 'Children')) ) % put fake gridlines behind real lines
    
    if new_objs
        legend_text = {'Average Electrical Power','Structural and PTO Cost'};
        scale_1 = 1;
        scale_2 = 1; %100;
    else
        scale_1 = 100; % convert $ to cents
        scale_2 = 1;
        cent = char(0162);
        legend_text = {['LCOE (' cent '/kWh)'],'c_v (%)'};
    end

    % objective heuristics
    sub2 = subplot(2,1,2); %figure
    plot(pct_angle, scale_1 * J1_pareto_ordered_normed,'Color',[0.4940 0.1840 0.5560]) % purple
    hold on
    plot(pct_angle, scale_2 * J2_pareto_ordered_normed,'Color',[0.4660 0.6740 0.1880]) % green
    grid on
    xlabel('Percent along the Pareto Curve')
    ylabel('Normalized Objective Value')
    improvePlot
    l2 = legend(legend_text,Location='eastoutside');

    set(gcf,"Position",[100 100 715 835]) % make wider so x major grid shows for every 20
    leg1.Position(1:2) = [.78 .43];
    sub1.Position(2:4) = [.5 .6 .4];
    sub2.Position(3:4) = [.6 .28];
    l2.Position(1:2) = [.54 .16];

    % nondimensionalized design variables (no front-point-to-front-point normalization)
    X_nondim = nondimensionalize_design_vars(overallX, p);
    X_pareto_nd = X_nondim(idxo,:);
    [X_pareto_nd_ordered,...
     ~, ~,...
     pct_angle_nd] = pareto_order_normalize(J1_pareto(idx_keep), J2_pareto(idx_keep), ...
                                            X_pareto_nd(idx_keep,:), dir,...
                                            J1_best, J1_worst, ...
                                            J2_best, J2_worst, [], false);
    [X_filtered_nd,pct_angle_even_nd] = low_pass_filter(pct_angle_nd, X_pareto_nd_ordered, backwards);

    f_nondim = figure;
    semilogy(pct_angle_even_nd, X_filtered_nd)
    grid on
    xlabel('Percent along the Pareto Curve')
    ylabel('Nondimensional Design Value')
    title('Nondimensional Design Trends')
    legend(nondim_var_names(var_names),'Location','eastoutside')
    improvePlot
end

function [filtered, t_even_spread] = low_pass_filter(time, signals, backwards)

    num_sigs = size(signals,2);

    windowSize = round(length(time) * 5/100);
    b = (1/windowSize) * ones(1,windowSize);
    a = 1;

    n_points_interp = 51;
    t_even_spread = linspace(min(time),max(time),n_points_interp);

    filtered = zeros(n_points_interp, num_sigs);
    
    for i=1:num_sigs
        % interpolate signal onto uniform time grid
        sig = signals(:,i);
        sig_even_spread = interp1(time,sig,t_even_spread).';

        % flip if filtering backwards in time
        if backwards
            sig_even_spread = flipud(sig_even_spread);
        end

        % pad, apply moving average filter, and crop away padding
        sig_padded = [ones(windowSize,1); sig_even_spread];
        yy = filter(b,a,sig_padded); 
        yy_crop = yy((windowSize+1):end);

        % flip if filtering backwards in time
        if backwards
            yy_crop = flipud(yy_crop); % apply filter backwards
        end

        filtered(:,i) = yy_crop;
    end
end

function [] = overlay_LCOE(p, LCOE_nom, LCOE_min)
    n_points = 30;
    P_elec_kW = xlim;
    C_design_M = ylim;
    P_elec_W = 1000*linspace(P_elec_kW(1), P_elec_kW(2), n_points);
    C_design = 1e6*linspace(C_design_M(1), C_design_M(2), n_points);

    [P_ELEC,C_DESIGN] = meshgrid(P_elec_W,C_design);
    LCOE = LCOE_from_capex_design_power(C_DESIGN, p.N_WEC, P_ELEC, p.FCR, p.eff_array);

    hold on
    levs = [LCOE_min;
            .4; .5; .6;
            LCOE_nom];
    grey = [.85 .85 .85];
    [~,h] = contour(P_ELEC/1000,C_DESIGN/1e6,LCOE,levs,'Color',grey,'ShowText','on','LabelSpacing',400);
    if isMATLABReleaseOlderThan("R2022b")
        h.LevelList = round(h.LevelList,3); % for old versions, round the contours directly. Will be slightly off from scatter points.
    else
        h.LabelFormat = '%0.2f'; % for new versions, just round the text
    end

    legend('LCOE ($/kWh)','Location','northwest')

end

function [X_pareto_ordered_normed,...
          J1_pareto_ordered_normed, ...
          J2_pareto_ordered_normed, pct_angle] = pareto_order_normalize(J1_pareto, J2_pareto, X_pareto, dir,  ...
                                                                        J1_best, J1_worst, J2_best, J2_worst,...
                                                                        X_best_J1, normalize_by_best)

    % sort from min J1 to max J1 (left to right)
    [J1_pareto_ordered,idx_order] = sort(J1_pareto);
    J2_pareto_ordered = J2_pareto(idx_order);
    X_pareto_ordered = X_pareto(idx_order,:);
    
    if normalize_by_best
        X_pareto_ordered_normed = X_pareto_ordered ./ repmat(X_best_J1,length(idx_order),1);
    else
        X_pareto_ordered_normed = X_pareto_ordered;
    end
    J1_pareto_ordered_normed = J1_pareto_ordered / J1_best;
    J2_pareto_ordered_normed = J2_pareto_ordered / J2_worst;

    % ranges
    J1_range = J1_best - J1_worst;
    J2_range = J2_best - J2_worst;

    % fraction along each objective
    frac_J1 = abs( (J1_worst - J1_pareto_ordered) / J1_range );
    frac_J2 = abs( (J2_worst - J2_pareto_ordered) / J2_range );

    % choose num and den to keep 0% corresponding to left (min J1) and 
    % 100% corresponding to right (max J1). See notebook p83 1/25/25
    if strcmp(dir(1),'max')
        num = frac_J1;
        den = frac_J2;
    elseif strcmp( dir(1),'min')
        num = frac_J2;
        den = frac_J1;
    else
        error('invalid direction string')
    end

    % find angle along circle with origin at nadir point - useful because 
    % diminishing returns often makes pareto look like a quarter circle
    angle = atan( num ./ den);

    % express angle as percentage: 0 to pi/2 maps 0 to 100
    pct_angle = 100/(pi/2) * angle;
    pct_angle(pct_angle==-100) = 100;
    
end

function X_nondim = nondimensionalize_design_vars(X_full, p)
    X = X_full(:,1:end-1);
    X_nondim = X;
    D_s = X(:,1);
    D_f = X(:,2);
    n_pts = size(X_full,1);
    F_uncon = nan(n_pts,1);
    P_uncon = nan(n_pts,1);
    for ii = 1:n_pts
        [~,~,~,val_i] = simulation(X_full(ii,:), p);
        F_uncon(ii) = max(val_i.force_ptrain/1e6, 1e-6);
        P_uncon(ii) = max(val_i.power_max/1e5, 1e-6);
    end
    X_nondim(:,1) = D_s ./ D_f;
    X_nondim(:,3) = X(:,3) ./ D_f;
    X_nondim(:,4) = X(:,4) ./ D_f;
    X_nondim(:,5) = X(:,5) ./ D_f;
    X_nondim(:,6) = X(:,6) ./ F_uncon;
    X_nondim(:,7) = X(:,7) ./ P_uncon;
    X_nondim(:,8) = (X(:,8)/1000) ./ D_f;
    X_nondim(:,9) = (X(:,9)/1000) ./ D_f;
    X_nondim(:,10) = (X(:,10)/1000) ./ D_f;
    X_nondim(:,11) = (X(:,11)/10) ./ D_f;
    X_nondim(:,12) = X(:,12) ./ D_f;
end

function names_out = nondim_var_names(names_in)
    names_out = names_in;
    names_out{1} = 'D_s/D_f';
    names_out{3} = 'T_{f,2}/D_f';
    names_out{4} = 'h_s/D_f';
    names_out{5} = 'h_{fs,clear}/D_f';
    names_out{6} = 'F_{max}/F_{max,unconstrained}';
    names_out{7} = 'P_{max}/P_{max,unconstrained}';
    names_out{8} = 't_{fb}/D_f';
    names_out{9} = 't_{sr}/D_f';
    names_out{10} = 't_d/D_f';
    names_out{11} = 'h_{stiff,f}/D_f';
    names_out{12} = 'h_{1,stiff,d}/D_f';
end

function f = lcoe_tangent_contours_plot(P_pareto_kW, C_pareto_M, p)
    f = figure;
    t = tiledlayout(2,2);
    t.TileSpacing = 'compact';

    P = P_pareto_kW(:) * 1000;
    C = C_pareto_M(:) * 1e6;
    [P,idx_sort] = sort(P);
    C = C(idx_sort);
    [P,ia] = unique(P,'stable');
    C = C(ia);

    ellipse = fit_ellipse_arc(P,C);

    alpha_non_design = 0.741;
    capex_indep_nom = (12.68e6 * p.N_WEC^(-alpha_non_design) + 1.24e6);
    alpha_opex = 0.5567;
    opex_nom = 1.193e6 * p.N_WEC^-alpha_opex;

    FCR_values = p.FCR .* [0.75 0.9 1.1 1.25];
    opex_vec = linspace(0.5*opex_nom, 1.5*opex_nom, 45);
    capex_indep_vec = linspace(0.5*capex_indep_nom, 1.5*capex_indep_nom, 45);
    [OPEX,CAPEX_INDEP] = meshgrid(opex_vec, capex_indep_vec);

    for i = 1:length(FCR_values)
        FCR_i = FCR_values(i);
        pct_star = nan(size(OPEX));
        for j = 1:numel(OPEX)
            pct_star(j) = tangent_percent_from_econ_terms(ellipse, FCR_i, OPEX(j), CAPEX_INDEP(j));
        end
        nexttile
        contourf(OPEX/1e6, CAPEX_INDEP/1e6, pct_star, 0:10:100, 'LineStyle','none')
        colorbar
        xlabel('OPEX design-independent ($M/yr)')
        ylabel('CAPEX design-independent ($M)')
        title(sprintf('FCR = %.3f', FCR_i))
        grid on
        improvePlot
    end
end

function ellipse = fit_ellipse_arc(P,C)
    p0 = [mean(P), mean(C), 0.6*(max(P)-min(P)), 0.6*(max(C)-min(C))];
    lb = [min(P)-2*range(P), min(C)-2*range(C), 1, 1];
    ub = [max(P)+2*range(P), max(C)+2*range(C), 10*range(P)+1, 10*range(C)+1];
    obj = @(q) sum(( ((P-q(1))./q(3)).^2 + ((C-q(2))./q(4)).^2 - 1 ).^2);
    opts = optimoptions('fmincon','Display','off');
    q = fmincon(obj,p0,[],[],[],[],lb,ub,[],opts);
    ellipse = struct('P0',q(1),'C0',q(2),'a',q(3),'b',q(4), ...
                     'Pmin',min(P),'Pmax',max(P));
end

function pct = tangent_percent_from_econ_terms(ellipse, FCR, opex, capex_indep)
    K = capex_indep + opex/FCR;
    f_root = @(P) P .* dC_dP_ellipse(ellipse, P) - C_ellipse(ellipse, P) - K;
    P_scan = linspace(ellipse.Pmin, ellipse.Pmax, 300);
    val = f_root(P_scan);
    idx = find(diff(sign(val))~=0,1,'first');
    if isempty(idx)
        [~,idx_min] = min(abs(val));
        P_star = P_scan(idx_min);
    else
        P_star = fzero(f_root, [P_scan(idx), P_scan(idx+1)]);
    end
    P_star = max(min(P_star, ellipse.Pmax), ellipse.Pmin);
    s = linspace(ellipse.Pmin, ellipse.Pmax, 500);
    C_s = C_ellipse(ellipse,s);
    ds = sqrt(diff(s).^2 + diff(C_s).^2);
    s_cum = [0 cumsum(ds)];
    s_star = interp1(s, s_cum, P_star, 'linear','extrap');
    pct = 100 * s_star / s_cum(end);
end

function C = C_ellipse(e, P)
    term = max(0, 1 - ((P - e.P0)./e.a).^2);
    C_upper = e.C0 + e.b * sqrt(term);
    C_lower = e.C0 - e.b * sqrt(term);
    if abs(mean(C_upper) - e.C0) < abs(mean(C_lower) - e.C0)
        C = C_lower;
    else
        C = C_upper;
    end
end

function dC = dC_dP_ellipse(e, P)
    denom = max(1e-12, sqrt(max(0, 1 - ((P - e.P0)./e.a).^2)));
    base = -e.b * (P - e.P0) ./ (e.a^2 .* denom);
    C_upper = e.C0 + e.b * sqrt(max(0, 1 - ((P - e.P0)./e.a).^2));
    C_lower = e.C0 - e.b * sqrt(max(0, 1 - ((P - e.P0)./e.a).^2));
    if abs(mean(C_upper) - e.C0) < abs(mean(C_lower) - e.C0)
        dC = -base;
    else
        dC = base;
    end
end
